import Swal from "@supportpal/sweetalert2";
import type { DeleteAttachmentData } from './types';

/**
 * Handles deletion of attachments
 */
export class AttachmentDeleter {
    /**
     * Static method to delete attachments.
     */
    static deleteAttachment(
        context: any,
        url: string | undefined,
        data: DeleteAttachmentData[],
        $listItem: any,
        successCallback?: (context: any) => void,
        silent?: boolean
    ): any {
        const name = $('<div/>').text($listItem.find('.filename').text()).html();
        const success = () => {
            // Call the success callback
            if (typeof successCallback === 'function') {
                successCallback.call(this, context);
            }

            // Remove the list item from the interface
            if (!silent) {
                Swal.fire(
                    Lang.get('messages.deleted'),
                    Lang.get('messages.success_deleted', { 'item': Lang.choice('general.attachment', 1) }),
                    'success'
                );
            }

            $listItem.remove();
        };

        // Send AJAX call to delete the attachment.
        if (!silent) {
            const params: any = {};
            // Special case, if there's no URL then there's no database record so just remove the item from the view.
            if (typeof url !== 'undefined') {
                params.ajax = {
                    url: url,
                    data: data
                };
            }
            (new deleteAlert(params))
                .fireDefault(Lang.choice('general.attachment', 1), name)
                .then((result: any) => {
                    if (result.value) {
                        success();
                    }
                });
        } else {
            // Special case, if there's no URL then there's no database record so just remove the item from the view.
            if (typeof url === 'undefined') {
                return success();
            }

            return $.ajax({ url: url, type: 'DELETE', data: data })
                .then((result: any) => {
                    if (result.status === 'success') {
                        success();
                    }
                });
        }
    }
}
