/**
 * Extend Number prototype with fileSize method
 */
declare global {
    interface Number {
        fileSize(): string;
    }
}

/**
 * Convert bytes into a human readable string
 */
export function initializeFileSizeUtility(): void {
    Object.defineProperty(Number.prototype, 'fileSize', {
        value: function (a?: any, b?: any, c?: any, d?: any): string {
            return (a = a ? [1e3, 'k', 'B'] : [1024, 'K', 'iB'], b = Math, c = b.log,
                    d = c(this as number) / c(a[0]) | 0, (this as number) / b.pow(a[0], d)).toFixed(2)
                + ' ' + (d ? (a[1] + 'MGTPEZY')[--d] + a[2] : 'Bytes');
        },
        writable: false,
        enumerable: false
    });
}

// Initialize immediately when this module is imported
initializeFileSizeUtility();
