// Import utility to enable fileSize() method on Number prototype
import './filesize-utils';

// Import types
import type { DeleteAttachmentData } from './types';

// Import and re-export the main FileUpload class
import { FileUpload } from './FileUpload';
export { FileUpload };

// Import the AttachmentDeleter for global event handlers
import { AttachmentDeleter } from './attachment-deleter';

/**
 * Register global event handlers when DOM is ready
 */
$(function () {
    /*
     * Handle deleting an existing attachment that belongs to a ticket message.
     */
    $(document).on('click', '.sp-message .sp-delete-attachment', function (this: any) {
        const data: DeleteAttachmentData[] = [];
        data.push({ name: 'id', value: $(this).data('attachment-id') });
        if (typeof $(this).data('token') !== 'undefined') {
            data.push({ name: 'token', value: $(this).data('token') });
        }

        AttachmentDeleter.deleteAttachment(
            this,
            $(this).data('url'),
            data,
            $(this).parents('li'),
            (context: any) => {
                // Grab the message that the attachment belongs to
                const $message = $(context).parents('.sp-message');

                // If we deleted the last attachment, hide the attachments area
                if ($message.find('ul.sp-attachments li[data-filename]').length === 1) {
                    $message.find('.sp-attachment, ul.sp-attachments').hide();
                }
            },
            false
        );
    });
});
