import Uppy from '@uppy/core';
import type { UppyFile, Meta } from '@uppy/utils';
import XHRUpload from '@uppy/xhr-upload';
import type { FileUploadParameters } from './types';
import { DragDropHandler } from './drag-drop-handler';

/**
 * Initializes and configures Uppy instance
 */
export class UppyInitializer {
    /**
     * Get the maximum file size from meta tag
     */
    static getMaxFileSize(): number {
        return Number($('meta[name="max_file_size"]').prop('content'));
    }

    /**
     * Create and configure a new Uppy instance
     */
    static createUppy(
        settings: Required<FileUploadParameters>,
        maxFileSize: number,
        onBeforeFileAdded: (currentFile: UppyFile<Meta, Record<string, never>>, files: { [key: string]: UppyFile<Meta, Record<string, never>> }) => UppyFile<Meta, Record<string, never>> | false
    ): Uppy<Meta, Record<string, never>> {
        // Get allowed file types
        const allowedFileTypesPattern = $('meta[name="allowed_files"]').prop('content');
        const allowedFileTypes = (allowedFileTypesPattern && allowedFileTypesPattern !== '*')
            ? allowedFileTypesPattern.split('|').filter((ext: string) => ext)
            : null;

        // Get upload URL from the file input or form
        const uploadUrl = settings.$element.data('url') || settings.$container.attr('action') || '/';

        /*
         * Initialise Uppy.
         */
        const uppy = new Uppy({
            autoProceed: true,
            restrictions: {
                maxFileSize: maxFileSize,
                allowedFileTypes: allowedFileTypes
            },
            onBeforeFileAdded: onBeforeFileAdded
        });

        // Add XHR Upload plugin
        uppy.use(XHRUpload, {
            endpoint: uploadUrl,
            fieldName: 'files[]',
            headers: () => ({
                'X-CSRF-TOKEN': $('meta[name="csrf_token"]').attr('content')
            }),
            formData: true,
        });

        // Add Drag & Drop handling if dropZone is specified
        if (settings.dropZone && settings.dropZone.length) {
            DragDropHandler.setup(settings.dropZone, settings.$container, uppy);
        }

        if (settings.$element && settings.$element.length) {
            UppyInitializer.setupFileInputHandler(settings.$element, uppy);
        }

        return uppy;
    }


    /**
     * Setup file input change handler
     */
    static setupFileInputHandler($element: any, uppy: Uppy<Meta, Record<string, never>>): void {
        $element.on('change', (e: any) => {
            const files = e.target.files;
            if (!files || files.length <= 0) {
                return;
            }

            // Add each selected file to Uppy
            for (let i = 0; i < files.length; i++) {
                try {
                    uppy.addFile({ name: files[i].name, type: files[i].type, data: files[i] });
                } catch (err: any) {
                    if (err.isRestriction) {
                        // Uppy restriction errors are handled by the 'restriction-failed' event
                    } else {
                        console.error('Error adding file to Uppy:', err);
                    }
                }
            }

            // Clear the file input so the same file can be selected again
            e.target.value = '';
        });
    }
}
